INSERT INTO `product` (`id`, `title`, `image`, `description`, `content`, `sell`, `view`, `rating`, `status`, `priority`, `tags`, `template`, `stock_manage`, `stop_selling`, `stock_quant`, `option_1`, `option_2`, `option_3`, `option_4`, `option_5`, `option_6`, `created_at`, `updated_at`, `raw_title`, `raw_full`) VALUES
(349, 'Ronald Jack RJ550A', 'Ronald Jack RJ550A.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'ronald jack rj550a', 'ronald jack rj550a máy chấm công sinh trắc học phổ biến có tính năng nhận dạng vân tay, hỗ trợ thẻ rfid, kết nối tcp / ip, xuất dữ liệu usb, theo dõi chấm công của nhân viên, màn hình lcd tích hợp và hỗ trợ hệ thống quản lý lực lượng lao động văn phòng. thích hợp cho các doanh nghiệp vừa và nhỏ.'),
(350, 'ZKTeco MB20', 'ZKTeco MB20.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'zkteco mb20', 'zkteco mb20 máy chấm công sinh trắc học được sử dụng rộng rãi hỗ trợ vân tay, nhận dạng khuôn mặt và xác minh mật khẩu. có màn hình tft, giao tiếp usb, mạng tcp / ip, công nghệ nhận dạng tốc độ cao, chức năng báo cáo chấm công và hỗ trợ quản lý truy cập văn phòng.'),
(351, 'Hikvision DS-K1T804MF', 'Hikvision DS-K1T804MF.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'hikvision ds-k1t804mf', 'hikvision ds-k1t804mf thiết bị đầu cuối chấm công vân tay chuyên nghiệp được thiết kế cho văn phòng và doanh nghiệp. tính năng xác thực vân tay, hỗ trợ rfid, quản lý dữ liệu chấm công, giao tiếp tcp / ip, sao lưu usb, thiết kế nhỏ gọn bền bỉ và xác minh nhân viên nhanh chóng.'),
(352, 'Suprema BioStation 3', 'Suprema BioStation 3.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'suprema biostation 3', 'suprema biostation 3 thiết bị chấm công sinh trắc học cấp doanh nghiệp có tính năng quét dấu vân tay tiên tiến, xác thực khuôn mặt, hỗ trợ thẻ rfid, kết nối đám mây, xử lý tốc độ cao, màn hình cảm ứng và quản lý bảo mật nâng cao cho môi trường văn phòng lớn.'),
(353, 'Dahua DHI-ASI1212F', 'Dahua DHI-ASI1212F.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'dahua dhi-asi1212f', 'dahua dhi-asi1212f máy chấm công và kiểm soát truy cập hiện đại hỗ trợ nhận dạng vân tay, xác thực rfid, theo dõi chấm công, giao tiếp mạng, hỗ trợ usb và các chức năng quản lý nhân viên tích hợp cho văn phòng và thương mại.'),
(354, 'Fellowes Powershred 79Ci', 'Fellowes Powershred 79Ci.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'fellowes powershred 79ci', 'fellowes powershred 79ci máy hủy giấy văn phòng hiệu suất cao được thiết kế để tiêu hủy tài liệu an toàn. có tính năng băm nhỏ, công nghệ chống kẹt, dung lượng 16 tờ, động cơ hoạt động liên tục, công nghệ an toàn safesense và hỗ trợ băm nhỏ giấy, đĩa cd, kim bấm và thẻ tín dụng.'),
(355, 'Bonsaii C149-C', 'Bonsaii C149-C.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'bonsaii c149-c', 'bonsaii c149-c máy hủy giấy văn phòng phổ biến có tính năng cắt ngang, dung lượng 18 tờ, hệ thống chống kẹt, giỏ rác lớn, thời gian chạy liên tục và hiệu suất băm nhỏ an toàn phù hợp cho việc xử lý tài liệu văn phòng.'),
(356, 'Aurora AS890C', 'Aurora AS890C.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'aurora as890c', 'aurora as890c máy hủy tài liệu văn phòng nhỏ gọn cung cấp khả năng hủy tài liệu bảo mật cắt ngang, dung lượng 8 tờ, hoạt động tự động khởi động / dừng, bảo vệ quá nhiệt và hoạt động yên tĩnh cho văn phòng tại nhà và doanh nghiệp nhỏ.'),
(357, 'Rexel Momentum X410', 'Rexel Momentum X410.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'rexel momentum x410', 'rexel momentum x410 máy hủy tài liệu văn phòng đáng tin cậy được thiết kế để tiêu hủy giấy an toàn. tính năng cắt ngang, dung lượng 10 tờ, công nghệ chống kẹt, thiết kế văn phòng nhỏ gọn, thời gian chạy liên tục và động cơ hoạt động êm ái.'),
(358, 'HSM Shredstar X10', 'HSM Shredstar X10.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'hsm shredstar x10', 'hsm shredstar x10 máy hủy tài liệu tập trung vào văn phòng có tính năng cắt ngang, tự động khởi động / dừng, công nghệ chống kẹt giấy, hoạt động ít tiếng ồn, thùng chứa chất thải trong suốt và hỗ trợ kẹp giấy và kim bấm.'),
(359, 'Epson TM-T82III', 'Epson TM-T82III.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'epson tm-t82iii', 'epson tm-t82iii máy in hóa đơn nhiệt được sử dụng rộng rãi được thiết kế cho các cửa hàng bán lẻ, nhà hàng và hệ thống pos. tính năng in nhiệt tốc độ cao, kết nối usb, thiết kế nhỏ gọn, tiết kiệm năng lượng, cơ chế cắt đáng tin cậy và khả năng tương thích với các hệ thống phần mềm pos chính.'),
(360, 'Xprinter XP-Q200II', 'Xprinter XP-Q200II.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'xprinter xp-q200ii', 'xprinter xp-q200ii máy in hóa đơn nhiệt giá cả phải chăng hỗ trợ in tốc độ cao, kết nối usb/lan, khả năng tương thích esc/pos, máy cắt tự động, thiết kế nhỏ gọn và hiệu suất ổn định cho các doanh nghiệp bán lẻ và nhà hàng.'),
(361, 'Rongta RP326', 'Rongta RP326.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'rongta rp326', 'rongta rp326 máy in hóa đơn pos phổ biến có công nghệ in nhiệt, tốc độ in cao, hỗ trợ usb và ethernet, thiết kế thương mại nhỏ gọn, máy cắt tự động và khả năng tương thích với hệ thống quản lý bán lẻ và khách sạn.'),
(362, 'Star Micronics TSP143III', 'Star Micronics TSP143III.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'star micronics tsp143iii', 'star micronics tsp143iii máy in hóa đơn đáng tin cậy được sử dụng rộng rãi trong các nhà hàng và cửa hàng bán lẻ trên toàn thế giới. tính năng in nhiệt, kết nối bluetooth/usb, hỗ trợ in trên đám mây, máy cắt giấy tự động, thiết kế nhỏ gọn và thiết lập dễ dàng cho môi trường pos.'),
(363, 'Bixolon SRP-350III', 'Bixolon SRP-350III.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'bixolon srp-350iii', 'bixolon srp-350iii máy in hóa đơn nhiệt chuyên nghiệp được thiết kế cho các hoạt động pos khối lượng lớn. có tốc độ in nhanh, hệ thống máy cắt bền, kết nối usb / ethernet, hoạt động tiết kiệm năng lượng và khả năng tương thích mạnh mẽ với các hệ thống pos thương mại.'),
(364, 'Epson Perfection V39 II', 'Epson Perfection V39 II.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'epson perfection v39 ii', 'epson perfection v39 ii máy quét phẳng nhỏ gọn được thiết kế cho các tác vụ quét văn phòng và tài liệu. tính năng quét độ phân giải cao, hoạt động hỗ trợ usb, hỗ trợ quét ảnh và tài liệu, thiết kế nhẹ và khả năng tương thích ocr cho quy trình làm việc năng suất.'),
(365, 'Canon CanoScan LiDE 400', 'Canon CanoScan LiDE 400.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'canon canoscan lide 400', 'canon canoscan lide 400 máy quét văn phòng phổ biến có kết nối usb-c tốc độ cao, quét tài liệu và ảnh độ phân giải cao, thiết kế tiết kiệm dọc nhỏ gọn, hỗ trợ ocr và tính di động nhẹ cho năng suất văn phòng.'),
(366, 'Fujitsu fi-8170', 'Fujitsu fi-8170.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'fujitsu fi-8170', 'fujitsu fi-8170 máy quét tài liệu chuyên nghiệp được thiết kế cho quy trình làm việc văn phòng doanh nghiệp. tính năng quét hai mặt, nạp tài liệu tốc độ cao, hỗ trợ ocr, khả năng tương thích mạng, xử lý giấy tiên tiến và khả năng số hóa tài liệu hàng loạt hiệu quả.'),
(367, 'Brother ADS-2200', 'Brother ADS-2200.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'brother ads-2200', 'brother ads-2200 máy quét tài liệu để bàn tốc độ cao có tính năng quét hai mặt, khay nạp tài liệu tự động, kết nối usb, hỗ trợ ocr, thiết kế nhỏ gọn và hiệu suất số hóa tài liệu văn phòng đáng tin cậy.'),
(368, 'HP ScanJet Pro 2600 f1', 'HP ScanJet Pro 2600 f1.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'hp scanjet pro 2600 f1', 'hp scanjet pro 2600 f1 máy quét năng suất văn phòng có tính năng quét phẳng và adf, hỗ trợ hai mặt, chức năng ocr, kết nối usb, thiết kế máy tính để bàn nhỏ gọn và quét hiệu quả để quản lý tài liệu kinh doanh.'),
(369, 'Epson EB-X06', 'Epson EB-X06.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'epson eb-x06', 'epson eb-x06 máy chiếu văn phòng phổ biến được thiết kế cho lớp học, cuộc họp và thuyết trình. có độ phân giải xga, độ sáng 3600 lumen, kết nối hdmi, công nghệ 3lcd, thiết kế di động và tuổi thọ đèn dài cho môi trường trình chiếu chuyên nghiệp.'),
(370, 'BenQ MX560', 'BenQ MX560.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'benq mx560', 'benq mx560 máy chiếu doanh nghiệp có độ phân giải xga, đầu ra độ sáng cao, hỗ trợ hdmi, chế độ sinh thái thông minh, tuổi thọ đèn dài và hiệu suất trình chiếu đáng tin cậy cho lớp học và phòng họp văn phòng.'),
(371, 'ViewSonic PA503X', 'ViewSonic PA503X.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'viewsonic pa503x', 'viewsonic pa503x máy chiếu văn phòng giá cả phải chăng có độ sáng 3800 lumen, độ phân giải xga, kết nối hdmi, công nghệ supercolor, độ trễ đầu vào thấp và hoạt động tiết kiệm năng lượng phù hợp cho các bài thuyết trình và hội nghị.'),
(372, 'Optoma EH412', 'Optoma EH412.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'optoma eh412', 'optoma eh412 máy chiếu văn phòng full hd được thiết kế để thuyết trình chuyên nghiệp và sử dụng đa phương tiện. có độ phân giải 1080p, độ sáng cao, kết nối hdmi, tuổi thọ đèn dài, loa tích hợp và thiết kế di động nhỏ gọn.'),
(373, 'Xiaomi Smart Projector 2', 'Xiaomi Smart Projector 2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'van-phong', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:30:00', '2024-05-14 04:30:00', 'xiaomi smart projector 2', 'xiaomi smart projector 2 máy chiếu thông minh nhỏ gọn hỗ trợ độ phân giải full hd, tích hợp android tv, kết nối không dây, loa tích hợp, công nghệ lấy nét tự động, giải trí di động và chức năng thuyết trình văn phòng.');
