INSERT INTO `product_translations` (`id`, `product_id`, `lang`, `title`, `description`, `content`, `created_at`, `updated_at`) VALUES
(349, 349, 'vi', 'Ronald Jack RJ550A', '', '<p>Máy chấm công sinh trắc học phổ biến có tính năng nhận dạng vân tay, hỗ trợ thẻ RFID, kết nối TCP / IP, xuất dữ liệu USB, theo dõi chấm công của nhân viên, màn hình LCD tích hợp và hỗ trợ hệ thống quản lý lực lượng lao động văn phòng. Thích hợp cho các doanh nghiệp vừa và nhỏ.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(350, 350, 'vi', 'ZKTeco MB20', '', '<p>Máy chấm công sinh trắc học được sử dụng rộng rãi hỗ trợ vân tay, nhận dạng khuôn mặt và xác minh mật khẩu. Có màn hình TFT, giao tiếp USB, mạng TCP / IP, công nghệ nhận dạng tốc độ cao, chức năng báo cáo chấm công và hỗ trợ quản lý truy cập văn phòng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(351, 351, 'vi', 'Hikvision DS-K1T804MF', '', '<p>Thiết bị đầu cuối chấm công vân tay chuyên nghiệp được thiết kế cho văn phòng và doanh nghiệp. Tính năng xác thực vân tay, hỗ trợ RFID, quản lý dữ liệu chấm công, giao tiếp TCP / IP, sao lưu USB, thiết kế nhỏ gọn bền bỉ và xác minh nhân viên nhanh chóng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(352, 352, 'vi', 'Suprema BioStation 3', '', '<p>Thiết bị chấm công sinh trắc học cấp doanh nghiệp có tính năng quét dấu vân tay tiên tiến, xác thực khuôn mặt, hỗ trợ thẻ RFID, kết nối đám mây, xử lý tốc độ cao, màn hình cảm ứng và quản lý bảo mật nâng cao cho môi trường văn phòng lớn.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(353, 353, 'vi', 'Dahua DHI-ASI1212F', '', '<p>Máy chấm công và kiểm soát truy cập hiện đại hỗ trợ nhận dạng vân tay, xác thực RFID, theo dõi chấm công, giao tiếp mạng, hỗ trợ USB và các chức năng quản lý nhân viên tích hợp cho văn phòng và thương mại.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(354, 354, 'vi', 'Fellowes Powershred 79Ci', '', '<p>Máy hủy giấy văn phòng hiệu suất cao được thiết kế để tiêu hủy tài liệu an toàn. Có tính năng băm nhỏ, công nghệ chống kẹt, dung lượng 16 tờ, động cơ hoạt động liên tục, công nghệ an toàn SafeSense và hỗ trợ băm nhỏ giấy, đĩa CD, kim bấm và thẻ tín dụng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(355, 355, 'vi', 'Bonsaii C149-C', '', '<p>Máy hủy giấy văn phòng phổ biến có tính năng cắt ngang, dung lượng 18 tờ, hệ thống chống kẹt, giỏ rác lớn, thời gian chạy liên tục và hiệu suất băm nhỏ an toàn phù hợp cho việc xử lý tài liệu văn phòng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(356, 356, 'vi', 'Aurora AS890C', '', '<p>Máy hủy tài liệu văn phòng nhỏ gọn cung cấp khả năng hủy tài liệu bảo mật cắt ngang, dung lượng 8 tờ, hoạt động tự động khởi động / dừng, bảo vệ quá nhiệt và hoạt động yên tĩnh cho văn phòng tại nhà và doanh nghiệp nhỏ.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(357, 357, 'vi', 'Rexel Momentum X410', '', '<p>Máy hủy tài liệu văn phòng đáng tin cậy được thiết kế để tiêu hủy giấy an toàn. Tính năng cắt ngang, dung lượng 10 tờ, công nghệ chống kẹt, thiết kế văn phòng nhỏ gọn, thời gian chạy liên tục và động cơ hoạt động êm ái.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(358, 358, 'vi', 'HSM Shredstar X10', '', '<p>Máy hủy tài liệu tập trung vào văn phòng có tính năng cắt ngang, tự động khởi động / dừng, công nghệ chống kẹt giấy, hoạt động ít tiếng ồn, thùng chứa chất thải trong suốt và hỗ trợ kẹp giấy và kim bấm.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(359, 359, 'vi', 'Epson TM-T82III', '', '<p>Máy in hóa đơn nhiệt được sử dụng rộng rãi được thiết kế cho các cửa hàng bán lẻ, nhà hàng và hệ thống POS. Tính năng in nhiệt tốc độ cao, kết nối USB, thiết kế nhỏ gọn, tiết kiệm năng lượng, cơ chế cắt đáng tin cậy và khả năng tương thích với các hệ thống phần mềm POS chính.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(360, 360, 'vi', 'Xprinter XP-Q200II', '', '<p>Máy in hóa đơn nhiệt giá cả phải chăng hỗ trợ in tốc độ cao, kết nối USB/LAN, khả năng tương thích ESC/POS, máy cắt tự động, thiết kế nhỏ gọn và hiệu suất ổn định cho các doanh nghiệp bán lẻ và nhà hàng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(361, 361, 'vi', 'Rongta RP326', '', '<p>Máy in hóa đơn POS phổ biến có công nghệ in nhiệt, tốc độ in cao, hỗ trợ USB và Ethernet, thiết kế thương mại nhỏ gọn, máy cắt tự động và khả năng tương thích với hệ thống quản lý bán lẻ và khách sạn.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(362, 362, 'vi', 'Star Micronics TSP143III', '', '<p>Máy in hóa đơn đáng tin cậy được sử dụng rộng rãi trong các nhà hàng và cửa hàng bán lẻ trên toàn thế giới. Tính năng in nhiệt, kết nối Bluetooth/USB, hỗ trợ in trên đám mây, máy cắt giấy tự động, thiết kế nhỏ gọn và thiết lập dễ dàng cho môi trường POS.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(363, 363, 'vi', 'Bixolon SRP-350III', '', '<p>Máy in hóa đơn nhiệt chuyên nghiệp được thiết kế cho các hoạt động POS khối lượng lớn. Có tốc độ in nhanh, hệ thống máy cắt bền, kết nối USB / Ethernet, hoạt động tiết kiệm năng lượng và khả năng tương thích mạnh mẽ với các hệ thống POS thương mại.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(364, 364, 'vi', 'Epson Perfection V39 II', '', '<p>Máy quét phẳng nhỏ gọn được thiết kế cho các tác vụ quét văn phòng và tài liệu. Tính năng quét độ phân giải cao, hoạt động hỗ trợ USB, hỗ trợ quét ảnh và tài liệu, thiết kế nhẹ và khả năng tương thích OCR cho quy trình làm việc năng suất.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(365, 365, 'vi', 'Canon CanoScan LiDE 400', '', '<p>Máy quét văn phòng phổ biến có kết nối USB-C tốc độ cao, quét tài liệu và ảnh độ phân giải cao, thiết kế tiết kiệm dọc nhỏ gọn, hỗ trợ OCR và tính di động nhẹ cho năng suất văn phòng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(366, 366, 'vi', 'Fujitsu fi-8170', '', '<p>Máy quét tài liệu chuyên nghiệp được thiết kế cho quy trình làm việc văn phòng doanh nghiệp. Tính năng quét hai mặt, nạp tài liệu tốc độ cao, hỗ trợ OCR, khả năng tương thích mạng, xử lý giấy tiên tiến và khả năng số hóa tài liệu hàng loạt hiệu quả.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(367, 367, 'vi', 'Brother ADS-2200', '', '<p>Máy quét tài liệu để bàn tốc độ cao có tính năng quét hai mặt, khay nạp tài liệu tự động, kết nối USB, hỗ trợ OCR, thiết kế nhỏ gọn và hiệu suất số hóa tài liệu văn phòng đáng tin cậy.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(368, 368, 'vi', 'HP ScanJet Pro 2600 f1', '', '<p>Máy quét năng suất văn phòng có tính năng quét phẳng và ADF, hỗ trợ hai mặt, chức năng OCR, kết nối USB, thiết kế máy tính để bàn nhỏ gọn và quét hiệu quả để quản lý tài liệu kinh doanh.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(369, 369, 'vi', 'Epson EB-X06', '', '<p>Máy chiếu văn phòng phổ biến được thiết kế cho lớp học, cuộc họp và thuyết trình. Có độ phân giải XGA, độ sáng 3600 lumen, kết nối HDMI, công nghệ 3LCD, thiết kế di động và tuổi thọ đèn dài cho môi trường trình chiếu chuyên nghiệp.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(370, 370, 'vi', 'BenQ MX560', '', '<p>Máy chiếu doanh nghiệp có độ phân giải XGA, đầu ra độ sáng cao, hỗ trợ HDMI, chế độ sinh thái thông minh, tuổi thọ đèn dài và hiệu suất trình chiếu đáng tin cậy cho lớp học và phòng họp văn phòng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(371, 371, 'vi', 'ViewSonic PA503X', '', '<p>Máy chiếu văn phòng giá cả phải chăng có độ sáng 3800 lumen, độ phân giải XGA, kết nối HDMI, công nghệ SuperColor, độ trễ đầu vào thấp và hoạt động tiết kiệm năng lượng phù hợp cho các bài thuyết trình và hội nghị.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(372, 372, 'vi', 'Optoma EH412', '', '<p>Máy chiếu văn phòng Full HD được thiết kế để thuyết trình chuyên nghiệp và sử dụng đa phương tiện. Có độ phân giải 1080p, độ sáng cao, kết nối HDMI, tuổi thọ đèn dài, loa tích hợp và thiết kế di động nhỏ gọn.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00'),
(373, 373, 'vi', 'Xiaomi Smart Projector 2', '', '<p>Máy chiếu thông minh nhỏ gọn hỗ trợ độ phân giải Full HD, tích hợp Android TV, kết nối không dây, loa tích hợp, công nghệ lấy nét tự động, giải trí di động và chức năng thuyết trình văn phòng.</p>', '2024-05-14 04:30:00', '2024-05-14 04:30:00');
